#include <iostream>
#include <string>
#include <sstream>
using namespace std;

int main() {
    string line, word;
    getline(cin, line);
    // 替换逗号为空格
    for (char& c : line) if (c == ',') c = ' ';
    stringstream ss(line);
    string longest, shortest;
    int maxLen = 0, minLen = 1000;
    while (ss >> word) {
        int len = word.length();
        if (len > maxLen) { maxLen = len; longest = word; }
        if (len < minLen) { minLen = len; shortest = word; }
    }
    cout << longest << endl << shortest << endl;
    return 0;
}

#include <iostream>
#include <climits>
using namespace std;

int main() {
    int n;
    cin >> n;
    long long demand[10000], dist[10000];
    for (int i = 0; i < n; i++)
        cin >> demand[i] >> dist[i];
    long long minCost = LLONG_MAX;
    int bestPos = 0;
    for (int i = 0; i < n; i++) {
        long long cost = 0, curDist = 0;
        for (int j = 0; j < n; j++) {
            int idx = (i + j) % n;
            cost += demand[idx] * curDist;
            curDist += dist[idx];
        }
        if (cost < minCost) { minCost = cost; bestPos = i; }
    }
    cout << bestPos << "," << minCost << endl;
    return 0;
}

