#include <iostream>
#include <string>
#include <set>
using namespace std;

void print(int d,const string&s){
    for(int i=0;i<d;i++)cout<<"|     ";
    cout<<s<<endl;
}

void solve(int d,set<string>&files,int&cnt){
    string s;
    while(cin>>s){
        if(s=="#"){cnt=-1;return;}
        if(s=="*")return;
        if(s[0]=='f')files.insert(s);
        else if(s[0]=='d'){
            print(d,s);
            set<string> sub;
            solve(d+1,sub,cnt);
            if(cnt==-1)return;
        }else if(s=="]"){
            for(const string&f:files)print(d,f);
            return;
        }
    }
}

int main(){
    int kase=1;
    while(true){
        string s;cin>>s;
        if(s=="#")break;
        if(kase>1)cout<<endl;
        cout<<"DATA SET "<<kase++<<":"<<endl<<"ROOT"<<endl;
        set<string> files;
        int cnt=0;
        if(s[0]=='f')files.insert(s);
        else if(s[0]=='d'){print(0,s);set<string>sub;solve(1,sub,cnt);}
        else if(s=="]"){for(const string&f:files)print(0,f);}
        if(cnt==0)solve(0,files,cnt);
    }
    return 0;
}

