#include <iostream>
#include <cstring>
#include <climits>
using namespace std;

int main(){
    int m,n,d[501]={},s[501]={},w[501][501]={},dp[501][501];
    cin>>m>>n;
    for(int i=1;i<m;i++){cin>>d[i];s[i+1]=s[i]+d[i];}
    for(int i=1;i<=m;i++)
        for(int j=i;j<=m;j++){
            int mid=(i+j)/2;
            for(int k=i;k<=j;k++) w[i][j]+=abs(s[k]-s[mid]);
        }
    memset(dp,0x3f,sizeof(dp));dp[0][0]=0;
    for(int i=1;i<=m;i++)
        for(int j=1;j<=n;j++)
            for(int k=0;k<i;k++)
                dp[i][j]=min(dp[i][j],dp[k][j-1]+w[k+1][i]);
    cout<<dp[m][n]<<endl;
    return 0;
}

