int main() {
    string a, b;
    cin >> a >> b;
    reverse(a.begin(), a.end());
    reverse(b.begin(), b.end());
    string res;
    int carry = 0;
    for (size_t i = 0; i < max(a.size(), b.size()); i++) {
        int da = i < a.size() ? a[i]-'0' : 0;
        int db = i < b.size() ? b[i]-'0' : 0;
        int s = da + db + carry;
        res += (s % 10) + '0';
        carry = s / 10;
    }
    if (carry) res += '1';
    reverse(res.begin(), res.end());
    cout << res << endl;
    return 0;
}

