#include <iostream>
#include <string>
#include <cstring>
using namespace std;

bool isCycle(const string& s) {
    int n = s.size();
    bool used[10] = {};
    for (char c : s) {
        if (used[c-'0']) return false;
        used[c-'0'] = true;
    }
    bool visited[60] = {};
    int pos = 0;
    for (int i = 0; i < n; i++) {
        if (visited[pos]) return false;
        visited[pos] = true;
        pos = (pos + (s[pos]-'0')) % n;
    }
    return pos == 0;
}

int main() {
    string s;
    cin >> s;
    cout << (isCycle(s) ? "yes" : "no") << endl;
    return 0;
}

