#include <iostream>
using namespace std;

bool isLeap(int y) {
    return (y%400==0) || (y%4==0 && y%100!=0);
}

int daysInMonth(int y, int m) {
    int d[] = {31,28,31,30,31,30,31,31,30,31,30,31};
    if (m==2 && isLeap(y)) return 29;
    return d[m-1];
}

int daysFromYearStart(int y, int m, int d) {
    int sum = d;
    for (int i=1; i<m; i++) sum += daysInMonth(y, i);
    return sum;
}

int main() {
    int y1,m1,d1,y2,m2,d2;
    cin>>y1>>m1>>d1>>y2>>m2>>d2;
    int days = 0;
    for (int y=y1; y<y2; y++) days += isLeap(y)?366:365;
    days -= daysFromYearStart(y1,m1,d1);
    days += daysFromYearStart(y2,m2,d2);
    cout << days << endl;
    return 0;
}

