#include <iostream>
#include <string>
#include <algorithm>
using namespace std;

bool isCycle(string s){
    int n=s.size();
    for(int k=1;k<=n;k++){
        string t;
        int carry=0;
        for(int i=n-1;i>=0;i--){
            int d=(s[i]-'0')*k+carry;
            t+=(d%10)+'0';
            carry=d/10;
        }
        if(carry) t+=(carry+'0');
        reverse(t.begin(),t.end());
        string doubled=s+s;
        if(doubled.find(t)==string::npos) return false;
    }
    return true;
}

int main(){
    string s;cin>>s;
    cout<<(isCycle(s)?"Yes":"No")<<endl;
    return 0;
}

