#include <iostream>
#include <string>
#include <algorithm>
using namespace std;

int main() {
    string a, b;
    cin >> a >> b;
    // Find decimal point positions
    int pa = a.find('.'), pb = b.find('.');
    if (pa == (int)string::npos) { a += '.'; a += '0'; pa = a.find('.'); }
    if (pb == (int)string::npos) { b += '.'; b += '0'; pb = b.find('.'); }
    string intA = a.substr(0, pa), intB = b.substr(0, pb);
    string fracA = a.substr(pa+1), fracB = b.substr(pb+1);
    // Pad fractional parts
    while (fracA.size() < fracB.size()) fracA += '0';
    while (fracB.size() < fracA.size()) fracB += '0';
    // Add fractional
    string fracSum;
    int carry = 0;
    for (int i = fracA.size()-1; i >= 0; i--) {
        int s = (fracA[i]-'0') + (fracB[i]-'0') + carry;
        fracSum += (s%10) + '0';
        carry = s/10;
    }
    reverse(fracSum.begin(), fracSum.end());
    // Add integer
    reverse(intA.begin(), intA.end());
    reverse(intB.begin(), intB.end());
    string intSum;
    for (size_t i = 0; i < max(intA.size(), intB.size()); i++) {
        int da = i < intA.size() ? intA[i]-'0' : 0;
        int db = i < intB.size() ? intB[i]-'0' : 0;
        int s = da + db + carry;
        intSum += (s%10) + '0';
        carry = s/10;
    }
    if (carry) intSum += '1';
    reverse(intSum.begin(), intSum.end());
    // Remove trailing zeros from fraction
    while (!fracSum.empty() && fracSum.back() == '0')
        fracSum.pop_back();
    if (fracSum.empty()) fracSum = "0";
    cout << intSum << '.' << fracSum << endl;
    return 0;
}

