#include <iostream>
using namespace std;
int digitSum(int num) {
int sum = 0;
while (num > 0) {
sum += num % 10;
num /= 10;
}
return sum;
}
int main() {
int N;
cin >> N;
for (int i = 0; i < N; ++i) {
int num;
cin >> num;
int baseSum = digitSum(num);
bool hasConstantSum = true;
for (int j = 2; j <= 9; ++j) {
int product = num * j;
int productSum = digitSum(product);
if (productSum != baseSum) {
hasConstantSum = false;
break;
}
}
if (hasConstantSum) {
cout << baseSum << endl;
} else {
cout << "NO" << endl;
}
}
return 0;
}

#include <iostream>
#include <string>
#include <vector>
using namespace std;
pair<int, int> parseAnswer(const string& answer) {
int x, y;
if (answer.find(';') != string::npos) {
int pos = answer.find(';');
x = stoi(answer.substr(0, pos));
y = stoi(answer.substr(pos + 1));
} else if (answer.find('/') != string::npos) {
int pos = answer.find('/');
x = stoi(answer.substr(0, pos));
y = stoi(answer.substr(pos + 1));
} else {
string paddedAnswer = string(4 - answer.length(), '0') + answer;
x = stoi(paddedAnswer.substr(0, 2));
y = stoi(paddedAnswer.substr(2));
}
return {x, y};
}
int main() {
int n, m;
cin >> n >> m;
vector<vector<char>> answerSheet(n, vector<char>(n, '.'));
for (int i = 0; i < m; ++i) {
string answer;
cin >> answer;
auto [x, y] = parseAnswer(answer);
answerSheet[n - y][x - 1] = '#';
}
for (const auto& row : answerSheet) {
for (char cell : row) {
cout << cell;
}
cout << endl;
}
return 0;
}

