int main(){
long long a, b, p, q; // 数据范围大，用long long
cin >> a >> b >> p >> q;
long long max_left = max(a, p);
long long min_right = min(b, q);
if (max_left > min_right) {
cout << "Disjoint" << endl;
} else {
bool nested1 = (a <= p && q <= b); // 第一个区间包含第二个
bool nested2 = (p <= a && b <= q); // 第二个区间包含第一个
if (nested1 || nested2)
cout << "Nested" << endl;
else
cout << "Overlap" << endl;
}
