}

#include <iostream>
using namespace std;
// 计算真因子和（不包括自身）
int getDivisorSum(int x) {
if (x <= 1) return 0; // 0和1没有真因子
int sum = 1; // 1是所有大于1的数的真因子
for (int i = 2; i * i <= x; i++) {
if (x % i == 0) {
sum += i;
if (i != x / i) sum += x / i; // 避免重复添加平方根
}
}
return sum;
}
int main() {
int M;
cin >> M;
while (M--) {
int A, B;
cin >> A >> B;
int sumA = getDivisorSum(A);
int sumB = getDivisorSum(B);
if (sumA == B && sumB == A) {
cout << "YES" << endl;
} else {
cout << "NO" << endl;
}
}
return 0;
}

