}

#include<stdio.h>
#include<string.h>
int main(int argc, char *argv[])
{
    char str[110];
    int len,i,k;
    int stack[110],end=0;
    while(scanf("%s",str)!=EOF)
    {
        printf("%s\n",str);
        end=0;
        len=strlen(str);
        for(i=0;i<len;i++)
        {
            if(str[i]!='('&&str[i]!=')') str[i]=' ';
        }
        for(i=0;i<len;i++)
        {
            if(str[i]=='(')
            {
                stack[end]=i;
                end++;
            }
            else if(str[i]==')')
            {
                if(end>0)//栈不为空，则
                {
                    k=stack[end-1];
                    str[k]=' ';//栈顶的左括号和新遇到的右括号匹配
                    str[i]=' ';
                    end--;//栈顶元素出栈 
                }
                else
                {
                    str[i]='?';//右括号不匹配 
                }
            }
        }
        while(end>0)
        {
            k=stack[end-1];
            str[k]='$';
            end--;
        }
         printf("%s\n",str);
    }
    return 0;
}

