#include <iostream>
#include <string>
#include <stack>
using namespace std;

int main(){
    string s;
    while(getline(cin,s)){
        cout<<s<<endl;
        string mark(s.size(),' ');
        stack<int> st;
        for(size_t i=0;i<s.size();i++){
            if(s[i]=='(')st.push(i);
            else if(s[i]==')'){
                if(st.empty())mark[i]='?';
                else st.pop();
            }
        }
        while(!st.empty()){mark[st.top()]='$';st.pop();}
        cout<<mark<<endl;
    }
    return 0;
}

