#include <iostream>
#include <string>
#include <stack>
using namespace std;

int main(){
    string s;
    while(getline(cin,s)){
        stack<char> ops;
        stack<int> vals;
        for(char c:s){
            if(c==' ')continue;
            if(c=='V')vals.push(1);
            else if(c=='F')vals.push(0);
            else if(c=='(')ops.push(c);
            else if(c==')'){
                while(ops.top()!='('){
                    char op=ops.top();ops.pop();
                    int b=vals.top();vals.pop();
                    if(op=='!')vals.push(!b);
                    else{int a=vals.top();vals.pop();
                        if(op=='&')vals.push(a&&b);
                        else vals.push(a||b);
                    }
                }
                ops.pop();
            }else{ops.push(c);}
        }
        while(!ops.empty()){
            char op=ops.top();ops.pop();
            int b=vals.top();vals.pop();
            if(op=='!')vals.push(!b);
            else{int a=vals.top();vals.pop();
                if(op=='&')vals.push(a&&b);
                else vals.push(a||b);
            }
        }
        cout<<(vals.top()?'V':'F')<<endl;
    }
    return 0;
}

