#include <algorithm>
using namespace std;

string myadd(string a,string b){
reverse(a.begin(),a.end());
reverse(b.begin(),b.end());
int len;
if(a.length()>b.length()){
len=a.length();
while(b.length()==len) b+=" ";
}else{
len=b.length();
while(a.length()==len) a+=" ";
}
int i=0,t=0;
string ans;
while(i<len){
t+=a[i]+b[i]-'0'-'0';
ans+=(t%10+'0');
t/=10;
i++;
}
if(t>0) ans+=t+'0';
reverse(ans.begin(),ans.end());
return ans;
}

