using namespace std;

const double EPS = 1e-9;

// 比较两个双精度浮点数是否相等（考虑精度误差）
bool doubleEqual(double a, double b) {
    return fabs(a - b) < EPS;
}

int main() {
    vector<double> nums(5);
    for (int i = 0; i < 5; ++i) {
        cin >> nums[i];
    }
    int count = 0;
    vector<int> result(4);
    // 四重循环遍历所有可能的四个下标组合
    for (int i = 0; i < 5; ++i) {
        for (int j = 0; j < 5; ++j) {
            if (i == j) continue;
            for (int k = 0; k < 5; ++k) {
                if (k == i || k == j) continue;
                for (int l = 0; l < 5; ++l) {
                    if (l == i || l == j || l == k) continue;
                    double val = fabs(nums[i] / nums[j] - nums[k] / nums[l]);
                    if (val < 0.5) {
                        count++;
                        if (count == 1) {
                            result = {i + 1, j + 1, k + 1, l + 1};
                        }
                    }
                }
            }
        }
    }
    cout << count << " ";
    for (int idx : result) {
        cout << idx << " ";
    }
    return 0;
}

