bool match(const string&s,const string&p){
    int n=s.size(),m=p.size();
    bool dp[21][21]={{true}};
    for(int j=1;j<=m;j++)dp[0][j]=dp[0][j-1]&&p[j-1]=='*';
    for(int i=1;i<=n;i++)
        for(int j=1;j<=m;j++){
            if(p[j-1]=='*')dp[i][j]=dp[i][j-1]||dp[i-1][j];
            else if(p[j-1]=='?'||p[j-1]==s[i-1])dp[i][j]=dp[i-1][j-1];
        }
    return dp[n][m];
}

int main(){
    string s,p;
    cin>>p>>s;
    cout<<(match(s,p)?"matched":"not matched")<<endl;
    return 0;
}

