#include <iostream>
#include <string>

using namespace std;

const int MOD = 1000000007;

int numDecodings(string s) {
int n = s.size();
if (n == 0 || s[0] == '0') return 0;

long long prev2 = 1; // dp[i-2]
long long prev1 = 1; // dp[i-1]
long long current = 0;

for (int i = 2; i <= n; ++i) {
current = 0;
char currentChar = s[i - 1];
if (currentChar >= '1' && currentChar <= '9') {
current = (current + prev1) % MOD;
}

string twoDigits = s.substr(i - 2, 2);
int num = stoi(twoDigits);
if (num >= 10 && num <= 25) {
current = (current + prev2) % MOD;
}

prev2 = prev1;
prev1 = current;
}

return static_cast<int>(prev1);
}

int main() {
string s;
cin >> s;
cout << numDecodings(s) << endl;
return 0;
}

