#include <iostream>
#include <string>
#include <vector>
#include <algorithm>
#include <unordered_map>
#include <queue>

// 计算二进制串的评分
int calcScore(const std::string& s) {
int score = 0, count = 1;
for (int i = 1; i <= s.size(); ++i) {
if (i == s.size() || s[i] != s[i - 1]) {
score ^= count;
count = 1;
} else {
++count;
}
}
return score;
}

// 广度优先搜索
void bfs(const std::string& start, std::unordered_map<int, std::pair<int, int>>& res) {
std::unordered_map<std::string, int> minSteps;
std::queue<std::string> q;
q.push(start);
minSteps[start] = 0;

while (!q.empty()) {
std::string s = q.front();
q.pop();
int score = calcScore(s);
int steps = minSteps[s];

if (res.find(score) == res.end()) {
res[score] = {1, steps};
} else {
res[score].first++;
res[score].second = std::min(res[score].second, steps);
}

for (int i = 0; i < s.size() - 1; ++i) {
std::string newStr = s;
std::swap(newStr[i], newStr[i + 1]);
if (minSteps.find(newStr) == minSteps.end()) {
minSteps[newStr] = steps + 1;
q.push(newStr);
}
}
}
}

int main() {
std::string s;
std::cin >> s;
std::unordered_map<int, std::pair<int, int>> res;
bfs(s, res);

std::vector<int> scores;
for (const auto& p : res) {
scores.push_back(p.first);
}
std::sort(scores.begin(), scores.end());

for (int score : scores) {
std::cout << score << " " << res[score].first << " " << res[score].second << std::endl;
}

return 0;
}

