using namespace std;

int N,K,P;vector<int>best,tmp;int maxSum=-1;

void dfs(int idx,int sum,int pSum,int last){
    if(idx==K){if(sum==N&&pSum>maxSum){maxSum=pSum;best=tmp;}return;}
    if(sum>=N)return;
    for(int i=last;i>=1;i--){
        int pw=pow(i,P);if(sum+pw>N||sum+pw+(K-idx-1)>N)continue;
        tmp.push_back(i);dfs(idx+1,sum+pw,pSum+i,i);tmp.pop_back();}
}

