int bfs(int A, int B, int N) {
unordered_map<int, int> dist = {{A, 0}};
queue<int> q = {A};
while (!q.empty())  {
int x = q.front();  q.pop();
if (x == B) return dist[x];
for (auto next : {x + 1, x - 1, x * N}) {
if (abs(next) <= 1e6 && dist.find(next)  == dist.end())  {
dist[next] = dist[x] + 1;
q.push(next);
}
}
}
return -1;
}

