#include <iostream>
using namespace std;
typedef long long ll;

// 递归计算在N×N网格中按Z序访问(i,j)的步数（1-based）
// 划分顺序：左上、右上、左下、右下
ll calc(ll n, ll i, ll j){
    if(n==1)return 1;
    ll mid=(n+1)/2; // 上半/左半的大小
    ll area=mid*mid; // 每个象限的近似大小
    if(i<=mid&&j<=mid)return calc(mid,i,j); // 左上
    if(i<=mid&&j>mid)return area*(n%2?1:1)+calc(mid,i,j-mid); // 右上
    if(i>mid&&j<=mid)return area*2+calc(n-mid,i-mid,j); // 左下
    return area*3+calc(n-mid,i-mid,j-mid); // 右下
}

int main(){
    int n,i,j;cin>>n>>i>>j;
    cout<<calc(n,i,j)<<endl;
    return 0;
}

