vector<string> grid;

void draw(int n, int r, int c){
    if(n==0){grid[r][c]='*';return;}
    int sz=1<<(n-1);
    // 左上角全部安全
    for(int i=r;i<r+sz;i++)for(int j=c;j<c+sz;j++)grid[i][j]='.';
    // 其余三个区域递归
    draw(n-1,r,c+sz);
    draw(n-1,r+sz,c);
    draw(n-1,r+sz,c+sz);
}

