bool similar(const string&a,const string&b){
    if(a==b)return true;
    if(abs((int)a.size()-(int)b.size())>1)return false;
    if(a.size()==b.size()){int diff=0;for(size_t i=0;i<a.size();i++)diff+=a[i]!=b[i];return diff==1;}
    if(a.size()>b.size()){for(size_t i=0;i<a.size();i++)if(a.substr(0,i)+a.substr(i+1)==b)return true;}
    else{for(size_t i=0;i<b.size();i++)if(b.substr(0,i)+b.substr(i+1)==a)return true;}
    return false;
}

