bool similar(const string&a,const string&b){
    int la=a.size(),lb=b.size();
    if(la==lb){int diff=0;for(int i=0;i<la;i++)if(a[i]!=b[i])diff++;return diff<=1;}
    if(la==lb+1){for(int i=0;i<la;i++)if(a.substr(0,i)+a.substr(i+1)==b)return true;}
    if(lb==la+1){for(int i=0;i<lb;i++)if(b.substr(0,i)+b.substr(i+1)==a)return true;}
    return false;}

