#include<iostream>
char a[1000][1000];
int d[1000][1000];
int w[1000][1000];
int n, m;

int qx[1000*1000];
int qy[1000*1000];

int dx[4] = {0, 1, 0, -1};
int dy[4] = {1, 0, -1, 0};


void bfs(int x, int y) {
qx[0] = x;
qy[0] = y;
d[x][y] = 1;
w[x][y] = 1;
int head = 0;
int tail = 1;
while (head < tail) {
int x = qx[head];
int y = qy[head];
head++;
for (int k = 0; k < 4; ++k) {
int nx = x + dx[k];
int ny = y + dy[k];
if (0 <= nx and nx < n and 0 <= ny and ny < m and a[nx][ny] == '.') {
if (d[nx][ny] == 0) {
d[nx][ny] = d[x][y] + 1;
w[nx][ny] = w[x][y];
qx[tail] = nx;
qy[tail] = ny;
tail++;
}
else if (d[nx][ny] == d[x][y] + 1) {
w[nx][ny] += w[x][y];
w[nx][ny] %= 1000000007;
}
}
}
}
}

