for (int i = 0; i <= N; ++i) g[i][i] = 0;
for (int i = 0; i < M; ++i) {
int u, v, w;
cin >> u >> v >> w;
g[u][v] = g[v][u] = w;
}
for (int k = 0; k <= N; ++k)
for (int i = 0; i <= N; ++i)
for (int j = 0; j <= N; ++j)
g[i][j] = min(g[i][j], g[i][k] + g[k][j]);
int K;
cin >> K;
int cnt = 0, best = -1, minCost = INF;
for (int i = 1; i <= K; ++i) {
int n;
cin >> n;
vector<int> p(n);
for (int &x : p) cin >> x;
bool ok = true;
int cost = 0;
for (int j = 1; j < n; ++j) if (g[p[j - 1]][p[j]] == INF) { ok = false; break; } else cost += g[p[j - 1]][p[j]];
if (!ok || g[0][p[0]] == INF || g[p[n - 1]][0] == INF) continue;
cost += g[0][p[0]] + g[p[n - 1]][0];
vector<bool> vis(N + 1, false);
for (int x : p) if (vis[x]) { ok = false; break; } else vis[x] = true;
if (!ok) continue;
cnt++;
if (cost < minCost) minCost = cost, best = i;
}
cout << cnt << endl << best << " " << minCost << endl;
}

#include <iostream>
#include <vector>
using namespace std;

pair<int, int> calcSkew(vector<int>& post, vector<int>& in, int ps, int pe, int is, int ie) {
if (ps > pe) return {0, 0};
int root = post[pe], idx = is;
while (in[idx] != root) idx++;
pair<int, int> left = calcSkew(post, in, ps, ps + idx - is - 1, is, idx - 1);
pair<int, int> right = calcSkew(post, in, ps + idx - is, pe - 1, idx + 1, ie);
return {left.first  + right.first  + (idx > is && idx == ie), left.second  + right.second  + (idx < ie && idx == is)};
}

int main() {
int n;
cin >> n;
vector<int> post(n), in(n);
for (int &x : post) cin >> x;
for (int &x : in) cin >> x;
pair<int, int> res = calcSkew(post, in, 0, n - 1, 0, n - 1);
cout << res.first  - res.second  << " = " << res.first  << " - " << res.second  << endl;
}

#include <iostream>
#include <vector>
using namespace std;

string checkHeap(const vector<int>& tree) {
int n = tree.size();
for (int i = 0; i < n; ++i) {
int l = 2 * i + 1, r = 2 * i + 2;
if (l < n && tree[i] > tree[l]) return "Min Heap";
if (r < n && tree[i] > tree[r]) return "Min Heap";
if (l < n && tree[i] < tree[l]) return "Max Heap";
if (r < n && tree[i] < tree[r]) return "Max Heap";
}
return "Not Heap";
}

void printPostOrder(const vector<int>& tree, int i, vector<int>& res) {
if (i >= tree.size())  return;
printPostOrder(tree, 2 * i + 1, res);
printPostOrder(tree, 2 * i + 2, res);
res.push_back(tree[i]);
}

int main() {
int m, n;
cin >> m >> n;
while (m--) {
vector<int> tree(n);
for (int &x : tree) cin >> x;
cout << checkHeap(tree) << endl;
vector<int> res;
printPostOrder(tree, 0, res);
for (int i = 0; i < res.size();  ++i) cout << res[i] << (i == res.size()  - 1 ? '\n' : ' ');
}
}

#include<iostream>
int a[2000], b[2000];
using i64 = long long;
const i64 mod = 998244353;
bool mem[2001][2001];
i64 cache[2001][2001];
i64 solve(int n, int m) {
if (n == 0 or m == 0) return 1;
if (mem[n][m]) return cache[n][m];
mem[n][m] = true;
auto reduce_a = solve(n-1, m);
auto reduce_b = solve(n, m-1);
if (a[n-1] != b[m-1]) {
auto reduce_ab = solve(n-1, m-1);
return cache[n][m] = (reduce_a + reduce_b - reduce_ab) % mod;
}
else
return cache[n][m] = (reduce_a + reduce_b) % mod;
}
int main(){
int n, m;
std::cin >> n >> m;
for (int i = 0; i < n; ++i) std::cin >> a[i];
for (int j = 0; j < m; ++j) std::cin >> b[j];
std::cout << (solve(n, m) + mod) % mod << "\n";
return 0;
}

