#include<iostream>
using namespace std;
typedef long long ll;
const ll maxn=25;
int n,G[maxn][maxn];
int head[maxn], color[maxn];
bool vis[maxn];
ll cnt , ret , ans = 1;

void check_dfs(int u){
vis[u] = true;
head[++cnt] = u;
for (int v=1; v<=n; ++v){
if(!vis[v] and G[u][v])
check_dfs(v);
}
}
void dfs(int step){
if (step > cnt) {
ret++;
return;
}
bool flag[4] ={0};
int u = head[step] ;
for (int i = 1; i <= cnt; ++i){
int v = head[i];
if(G[u][v])
flag[color[v]] = true;
}
for (color[u] = 1; color[u] <= 3; ++color[u])
if (!flag[color[u]])  dfs(step+1);
color[u] = 0;
}
