cin >> G[i][j];
G[j][i] = G[i][j];
}
}
for (int i=1; i<=n; ++i)
if (!vis[i]) {
cnt = 0;
check_dfs(i);
color[i] = 1;

ret = 0;
dfs(2);
ans *= 3*ret;
}
cout << ans << endl;
return 0;
}

