#include<iostream>
using LL = long long;
const LL mod = 1000000007;
struct Node{
LL first,second;
};
Node exp()  {
char op;
std::cin >> op;
if (op == '|') {
auto left = exp();
auto right = exp();
auto neg = left.first * right.first;
auto pos = left.first * right.second
+left.second * right.first
+left.second * right.second
;
return {neg % mod, pos % mod};
}
else if (op == '&') {
auto left = exp();
auto right = exp();
auto neg = left.first * right.first
+left.second * right.first
+left.first * right.second;
auto pos = left.second * right.second;
return {neg % mod, pos % mod};
}
else if (op == '^') {
auto left = exp();
auto right = exp();
auto neg = left.first * right.first
+left.second * right.second;
auto pos = left.second * right.first
+left.first * right.second;
return {neg % mod, pos % mod};
}
else if (op == '1') {
return {0, 1};
}
else if (op == '0') {
return {1, 0};
}
else {
return {1, 1};
}
}
int main() {
std::cout << exp().first << "\n";
return 0;
}


3、联盟
题目描述
在国际会议上，共有 nn 个国家需要加入三个联盟中的一个。任何两个接壤的国家不能加入相同的联盟。现在给出各国的接壤情况，请计算存在多少种合法的联盟分配方案。
输入格式
第一行：单个整数 nn 表示国家数量
第二行到第 nn 行：在第 i+1i+1 行有 n−in−i 个整数 ci,i+1,ci,i+2,…,ci,nci,i+1​,ci,i+2​,…,ci,n​，其中
ci,j=0ci,j​=0 表示 ii 号国家与 jj 号国家不接壤
ci,j=1ci,j​=1 表示 ii 号国家与 jj 号国家接壤
输出格式
单个整数：表示合法的联盟分配方案总数。
输入样例#1
3
1 1
1
输出样例#1
6
输入样例#2
4

#include<iostream>
#include<vector>
#include<cmath>
using namespace std;
const int maxn = 10010;
vector<int> robot[maxn];
int n, m, a, b, t[maxn], mem[maxn], ans;

int cal(int x) {
if (mem[x]) return mem[x];
int maxt = 0;
for (int next_robot : robot[x])
maxt = max(maxt, cal(next_robot));
return mem[x] = maxt + t[x];
}

int main() {
cin >> n >> m;
for (int i = 1; i <= n; i++) cin >> t[i];
while (m--) {
cin >> a >> b;
robot[a].push_back(b);
}
for (int i = 1; i <= n; i++)
ans = max(ans, cal(i));
cout << ans ;
return 0;
}

