using namespace std;
using LL = long long;

const int kN = 1e6 + 5;
const int Mod = 998244353;

int n;
LL m;
int a[kN];

struct matrix {
int a[2][2];

int* operator[] (int x) {
return a[x];
}

friend matrix operator* (matrix a, matrix b) {
matrix c;
for (int i = 0; i < 2; ++i) {
for (int j = 0; j < 2; ++j) {
c[i][j] = 0;
}
}
for (int i = 0; i < 2; ++i) {
for (int j = 0; j < 2; ++j) {
for (int k = 0; k < 2; ++k) {
c[i][j] = (c[i][j] + 1ll * a[i][k] * b[k][j]) % Mod;
}
}
}
return c;
}

friend vector<int> operator* (matrix a, vector<int> b) {
vector<int> c(2);
for (int i = 0; i < 2; ++i) {
c[i] = 0;
for (int j = 0; j < 2; ++j) {
c[i] = (c[i] + 1ll * a[i][j] * b[j]) % Mod;
}
}
return c;
}
};

matrix qpow (matrix x, LL y) {
matrix r;
r[0][0] = 1, r[0][1] = 0;
r[1][0] = 0, r[1][1] = 1;
for (; y; y >>= 1) {
if (y & 1) r = r * x;
x = x * x;
}
return r;
}

