}

#include<iostream>
#include<algorithm>
#include<vector>
#include<stack>
const int sz=3e5+10;
struct edge{
int nxt,to;
}graph[sz<<3];
int head[sz],hpp=1;
void addEdge(int from,int to){
graph[++hpp]=edge{head[from],to};
head[from]=hpp;
}
int dfn[sz],low[sz],dpp,edcc,belong[sz];
std::vector<int>points[sz];
std::stack<int>s;
void tarjan(int u,int pid){
dfn[u]=low[u]=++dpp;
s.push(u);
for(int p=head[u];p;p=graph[p].nxt){
int v=graph[p].to;
if(dfn[v]==0)tarjan(v,p),low[u]=std::min(low[u],low[v]);
else if((p^1)!=pid)low[u]=std::min(low[u],dfn[v]);
}
if(dfn[u]==low[u]){
++edcc;
while(!s.empty()){
int v=s.top();
s.pop();
points[edcc].push_back(v);
belong[v]=edcc;
if(v==u)break;
}
}
}
std::vector<int>tree[sz];
int size[sz],max[sz];
void dfs(int u,int fau){
size[u]=points[u].size(),max[u]=0;
for(int v:tree[u]){
if(v==fau)continue;
dfs(v,u);
size[u]+=size[v];
max[u]=std::max(max[u],size[v]);
}
}
int main(){
// freopen("game.in","r",stdin);
// freopen("game.out","w",stdout);
int n,m;
std::cin>>n>>m;
std::fill(head+1,head+n+1,0),hpp=1;
for(int i=1,u,v;i<=m;i++)
std::cin>>u>>v,addEdge(u,v),addEdge(v,u);
std::fill(dfn+1,dfn+n+1,0);
for(int i=1;i<=edcc;i++)tree[i].clear(),points[i].clear();
edcc=0;
for(int u=1;u<=n;u++)
if(dfn[u]==0)tarjan(u,0);
for(int u=1;u<=n;u++){
for(int p=head[u];p;p=graph[p].nxt){
int v=graph[p].to;
if(belong[u]!=belong[v])tree[belong[u]].push_back(belong[v]);
}
}
dfs(1,0);
for(int i=1;i<=n;i++)std::cout<<std::max(max[belong[i]],n-size[belong[i]])+1<<" ";
std::cout<<"\n";
return 0;
}

